# weighted score emphasize electrochem-related
weights = {t:1 for t in sel_terms}
for t in ['electrochem','electrodeposition','electroplating','electrolyte','electrowinning','electrorefining','electrocatal','molten salt','corrosion','battery','batteries','energy storage','energy conversion']:
    weights[t]=3
for t in ['autonomous','high-throughput','closed-loop','automation','robot','data-driven','machine learning','artificial intelligence','optimization']:
    weights[t]=2
